233	template<typename T>
234	__global__ void cuda_random_uniform_kernel(T* buffer, const size_t size, const int seq_offset)
235	{
236	    const int     idx = blockIdx.x * blockDim.x + threadIdx.x;
237	    curandState_t local_state;
238	    curand_init((unsigned long long int)1337, idx + seq_offset, 0, &local_state);
239	    for (size_t index = idx; index < size; index += blockDim.x * gridDim.x) {
240	        buffer[index] = (T)(curand_uniform(&local_state) * 0.2f - 0.1f);
241	    }
242	}
