297	// loads data from binary file. If it succeeds, returns a non-empty vector. If loading fails or
298	// the product of the elements in shape is 0, this function will return an empty vector.
299	template<typename T>
300	std::vector<T> loadWeightFromBinHelper(std::vector<size_t> shape, std::string filename)
301	{
302	    if (shape.size() > 2) {
303	        printf("[ERROR] shape should have less than two dims \n");
304	        return std::vector<T>();
305	    }
306	    size_t dim0 = shape[0], dim1 = 1;
307	    if (shape.size() == 2) {
308	        dim1 = shape[1];
309	    }
310	    size_t size = dim0 * dim1;
311	    if (size == 0) {
312	        FT_LOG_WARNING("shape is zero, skip loading weight from file %s \n", filename.c_str());
313	        return std::vector<T>();
314	    }
315	
316	    std::vector<T> host_array(size);
317	    std::ifstream  in(filename, std::ios::in | std::ios::binary);
318	    if (!in.is_open()) {
319	        FT_LOG_WARNING("file %s cannot be opened, loading model fails! \n", filename.c_str());
320	        return std::vector<T>();
321	    }
322	
323	    size_t loaded_data_size = sizeof(T) * size;
324	    in.seekg(0, in.end);
325	    in.seekg(0, in.beg);
326	
327	    FT_LOG_DEBUG("Read " + std::to_string(loaded_data_size) + " bytes from " + filename);
328	    in.read((char*)host_array.data(), loaded_data_size);
329	
330	    size_t in_get_size = in.gcount();
331	    if (in_get_size != loaded_data_size) {
332	        FT_LOG_WARNING("file %s only has %ld, but request %ld, loading model fails! \n",
333	                       filename.c_str(),
334	                       in_get_size,
335	                       loaded_data_size);
336	        return std::vector<T>();
337	    }
338	    in.close();
339	    // If we succeed, return an array with values.
340	    return host_array;
341	}
342	
343	template<typename T, typename T_IN>
344	int loadWeightFromBinFunc(T* ptr, std::vector<size_t> shape, std::string filename)
345	{
346	    std::vector<T_IN> host_array = loadWeightFromBinHelper<T_IN>(shape, filename);
347	
348	    if (host_array.empty()) {
349	        return 0;
350	    }
351	
352	    if (std::is_same<T, T_IN>::value == true) {
353	        cudaH2Dcpy(ptr, (T*)host_array.data(), host_array.size());
354	    }
355	    else {
356	        T_IN* ptr_2 = nullptr;
357	        deviceMalloc(&ptr_2, host_array.size(), false);
358	        cudaH2Dcpy(ptr_2, host_array.data(), host_array.size());
359	        invokeCudaD2DcpyConvert(ptr, ptr_2, host_array.size());
360	        deviceFree(ptr_2);
361	    }
362	    return 0;
363	}
