441	template<typename T, typename T_IN>
442	int loadWeightFromBinAndQuantizeForWeightOnlyFunc(int8_t*             ptr,
443	                                                  T*                  scales_ptr,
444	                                                  std::vector<size_t> shape,
445	                                                  std::string         filename)
446	{
447	    FT_LOG_INFO(std::string("Loading and quantizing weight from file: ") + filename);
448	    FT_CHECK_WITH_INFO(shape.size() == 2, "We can only use this function to dequantize a weight matrix.");
449	    std::vector<T_IN> host_array = loadWeightFromBinHelper<T_IN>(shape, filename);
450	
451	    if (host_array.empty()) {
452	        return 0;
453	    }
454	
455	    const size_t        num_elts = shape[0] * shape[1];
456	    std::vector<int8_t> host_quantized_weight_buf(num_elts);
457	    std::vector<T>      host_scales_buf(shape[1]);
458	
459	    // Note: This function preprocesses the weights to a special format for weight only quant!
460	    symmetric_quantize<T, T_IN>(host_quantized_weight_buf.data(),
461	                                host_scales_buf.data(),
462	                                host_array.data(),
463	                                shape,
464	                                QuantType::INT8_WEIGHT_ONLY);
465	
466	    cudaH2Dcpy(ptr, (int8_t*)host_quantized_weight_buf.data(), host_quantized_weight_buf.size());
467	    cudaH2Dcpy(scales_ptr, (T*)host_scales_buf.data(), host_scales_buf.size());
468	
469	    return 0;
470	}
