706	template<typename T_OUT, typename T_IN>
707	__global__ void transpose(T_OUT* dst, T_IN* src, const int dim0, const int dim1)
708	{
709	    for (size_t tid = threadIdx.x + blockIdx.x * blockDim.x; tid < dim0 * dim1; tid += blockDim.x * gridDim.x) {
710	        const int src_col_id                = tid % dim1;
711	        const int src_row_id                = tid / dim1;
712	        dst[src_col_id * dim0 + src_row_id] = (T_OUT)(src[tid]);
713	    }
714	}
