732	template<typename T_OUT, typename T_IN>
733	__global__ void transpose0213(T_OUT* dst, T_IN* src, const int dim0, const int dim1, const int dim2, const int dim3)
734	{
735	    // src permutation: [0, 1, 2, 3]
736	    // dst permutation: [0, 2, 1, 3]
737	    for (size_t tid = threadIdx.x + blockIdx.x * blockDim.x; tid < dim0 * dim1 * dim2 * dim3;
738	         tid += blockDim.x * gridDim.x) {
739	        int       tmp_idx   = tid;
740	        const int dim_3_idx = tmp_idx % dim3;
741	        tmp_idx             = (tmp_idx - dim_3_idx) / dim3;
742	        const int dim_2_idx = tmp_idx % dim2;
743	        tmp_idx             = (tmp_idx - dim_2_idx) / dim2;
744	        const int dim_1_idx = tmp_idx % dim1;
745	        tmp_idx             = (tmp_idx - dim_1_idx) / dim1;
746	        const int dim_0_idx = tmp_idx % dim0;
747	        dst[dim_0_idx * dim1 * dim2 * dim3 + dim_2_idx * dim1 * dim3 + dim_1_idx * dim3 + dim_3_idx] = src[tid];
748	    }
749	}
