755	    // Note that this kernel is used for pre-processing and not very efficient.
756	    cudaD2Dcpy(workspace, data, dim0 * dim1 * dim2 * dim3);
757	    transpose0213<<<256, 256>>>(data, workspace, dim0, dim1, dim2, dim3);
758	}
