771	template<typename T_OUT, typename T_IN>
772	__global__ void transpose102(T_OUT* dst, T_IN* src, const int dim0, const int dim1, const int dim2)
773	{
774	    // src permutation: [0, 1, 2]
775	    // dst permutation: [1, 0, 2]
776	    for (size_t tid = threadIdx.x + blockIdx.x * blockDim.x; tid < dim0 * dim1 * dim2; tid += blockDim.x * gridDim.x) {
777	        int       tmp_idx                                           = tid;
778	        const int dim_2_idx                                         = tmp_idx % dim2;
779	        tmp_idx                                                     = (tmp_idx - dim_2_idx) / dim2;
780	        const int dim_1_idx                                         = tmp_idx % dim1;
781	        tmp_idx                                                     = (tmp_idx - dim_1_idx) / dim1;
782	        const int dim_0_idx                                         = tmp_idx % dim0;
783	        dst[dim_1_idx * dim0 * dim2 + dim_0_idx * dim2 + dim_2_idx] = src[tid];
784	    }
785	}
