884	__global__ void check_range(T* buffer, size_t size, T min, T max, bool* d_within_range)
885	{
886	    for (int i = blockIdx.x * blockDim.x + threadIdx.x; i < size; i += blockDim.x * gridDim.x) {
887	        const T val = buffer[i];
888	        if (val < min || val > max) {
