896	{
897	    cudaMemsetAsync(d_within_range, true, sizeof(bool), stream);
898	
899	    dim3 block(256);
900	    dim3 grid((size + 255) / 256);
901	    check_range<T><<<grid, block, 0, stream>>>(buffer, size, min, max, d_within_range);
902	
903	    bool result;
904	    cudaD2Hcpy(&result, d_within_range, 1);
905	    return result;
906	}
